# OEIS sequence: A036504

from sympy import factorint
from sympy.ntheory.factor_ import digits
def A036504(n):
    m = n**(n-1)
    for p, e in factorint(n).items():
        m //= p**min(e*(n-1),(n-sum(digits(n,p)[1:]))//(p-1))
    return m # _Chai Wah Wu_, May 03 2026

